from argparse import ArgumentParser

class CustomArgumentParser(ArgumentParser):
    def __init__(self):
        super().__init__()
        self.default_values = {}

    def parse_arguments(self, command_string):
        args = command_string.split()[1:]
        for arg in args:
            if arg.startswith('--'):
                key_value = arg[2:].split('=')
                if len(key_value) == 2:
                    self.arguments[key_value[0]] = self._convert_type(key_value[0], key_value[1])
                else:
                    self.arguments[key_value[0]] = self.default_values.get(key_value[0], True)
            elif arg.startswith('-'):
                key = arg[1:]
                if arg in self.arguments:
                    self.arguments[key] = self._convert_type(key, '')
                else:
                    self.arguments[key] = True
        missing_args = self.required - set(self.arguments.keys())
        if missing_args:
            return False, missing_args

        return True, None

